#!/bin/bash
#SBATCH -c 8
#SBATCH -p hopper
#SBATCH -w ruapehu
#SBATCH --gres=gpu:1
#SBATCH --job-name=entropy_exp
#SBATCH --tasks-per-node=1
#SBATCH --output=%x-%j.out
#SBATCH --time=11:59:00
#SBATCH --array=0-5

# Entropy-vs-refusal search experiment.
# The override matrix is generated by scripts/entropy_experiment_runs.py
# (edit MODEL_PATHS there if checkpoints moved). Each array task runs one cell;
# results land in debug_search/entropy_exp/<signal>/<unl>/<dataset>/<model>/.
#
# SUBSET via env vars (comma lists); empty = all. The matrix is generated
# fresh each task, so the env filter + --array range must agree. Check first:
#   EXP_UNLEARNINGS=LUNAR EXP_MODELS=llama3-8b-instruct \
#       python scripts/entropy_experiment_runs.py --count   # -> set --array=0-(N-1)
#
# DEFAULT below = the 6-run smoke test (LUNAR, llama3, both datasets, all signals)
# to validate the new code path before committing GPU hours. To run everything,
# clear the EXP_* defaults and change to --array=0-53.
#
# After tasks finish:
#   python scripts/entropy_vs_refusal_analysis.py \
#       --root debug_search/entropy_exp --live --out entropy_search_live.md

: "${EXP_DATASETS:=}"
: "${EXP_UNLEARNINGS:=LUNAR}"
: "${EXP_MODELS:=llama3-8b-instruct}"
: "${EXP_SIGNALS:=}"

source /nfs-share/ahta3/workspace/LUNAR/.venv/bin/activate

export HF_TOKEN=$(cat /nfs-share/ahta3/.huggingface_token)
export NETRC=/nfs-share/ahta3/.wandb_token

cd /nfs-share/ahta3/workspace/LUNAR/

GEN_ARGS=""
[ -n "$EXP_DATASETS" ]    && GEN_ARGS="$GEN_ARGS --datasets $EXP_DATASETS"
[ -n "$EXP_UNLEARNINGS" ] && GEN_ARGS="$GEN_ARGS --unlearnings $EXP_UNLEARNINGS"
[ -n "$EXP_MODELS" ]      && GEN_ARGS="$GEN_ARGS --models $EXP_MODELS"
[ -n "$EXP_SIGNALS" ]     && GEN_ARGS="$GEN_ARGS --signals $EXP_SIGNALS"

mapfile -t RUNS < <(python scripts/entropy_experiment_runs.py $GEN_ARGS)

echo "Task ${SLURM_ARRAY_TASK_ID}/${#RUNS[@]}: ${RUNS[$SLURM_ARRAY_TASK_ID]}"
srun python -u -m run_attack --config config/tas.yaml ${RUNS[$SLURM_ARRAY_TASK_ID]}

# Copy this task's SLURM log into its per-run output_dir (parsed from the run args).
# Note: the .out is still open, so the very last lines written after this copy
# (final flushes) won't be captured — fine for inspecting logs alongside results.
DEST=$(grep -oP 'output_dir=\K[^ ]+' <<<"${RUNS[$SLURM_ARRAY_TASK_ID]}")
OUT_FILE="${SLURM_JOB_NAME}-${SLURM_JOB_ID}.out"
if [ -n "$DEST" ] && [ -f "$OUT_FILE" ]; then
    mkdir -p "$DEST"
    cp "$OUT_FILE" "$DEST/"
    echo "Copied $OUT_FILE -> $DEST/"
fi